import{_ as t,o,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"67. Reasonable Adjustments For Employees With A Disability","description":"","frontmatter":{"title":"67. Reasonable Adjustments For Employees With A Disability","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/workplace-rights/67-reasonable-adjustments-for-employees-with-a-disability.md","filePath":"ebas/mental-health/common-terms/workplace-rights/67-reasonable-adjustments-for-employees-with-a-disability.md"}'),n={name:"ebas/mental-health/common-terms/workplace-rights/67-reasonable-adjustments-for-employees-with-a-disability.md"};function i(r,e,l,p,m,h){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_67-reasonable-adjustments-for-employees-with-a-disability" tabindex="-1">67. Reasonable Adjustments For Employees With A Disability <a class="header-anchor" href="#_67-reasonable-adjustments-for-employees-with-a-disability" aria-label="Permalink to &quot;67. Reasonable Adjustments For Employees With A Disability&quot;">​</a></h1><p><strong>67.1</strong> Purpose</p><p><strong>67.2</strong> The purpose of this clause is to reflect the obligations of the EO Act with respect to reasonable adjustments for Employees with a disability. The obligations apply regardless of whether the disability is or has been the subject of a Workcover claim.</p><p><strong>67.3</strong> Definitions</p><p><strong>(a)</strong> Disability has the same meaning as s. 4 of the EO Act and includes:</p><p><strong>(i)</strong> Total or partial loss of a bodily function; or</p><p><strong>(ii)</strong> Presence in the body of organisms that may cause disease</p><p><strong>(iii)</strong> Total or partial loss of a part of the body; or</p><p><strong>(iv)</strong> Malfunction of a part of the body including: <strong>(A)</strong> a mental or psychological disease or disorder; or <strong>(B)</strong> condition or disorder that results in a person learning more slowly than those without the condition or disorder</p><p><strong>(v)</strong> malformation or disfigurement of a part of the body, and includes a disability which is temporary or ongoing and that may exist in the future (including because of a genetic predisposition to that disability) and, to avoid doubt, behaviour that is a symptom or manifestation of a disability.</p><p><strong>(b)</strong> Reasonable adjustments has the same meaning as s. 20 of the EO Act and requires consideration of all relevant facts and circumstances including:</p><p><strong>(i)</strong> The Employee’s circumstances, including the nature of the disability</p><p><strong>(ii)</strong> The nature of the Employee’s role</p><p><strong>(iii)</strong> The nature of the adjustment required to accommodate the Employee’s disability</p><p><strong>(iv)</strong> The financial circumstances of the Employer</p><p><strong>(v)</strong> The size and nature of the workplace and the Employer’s business</p><p><strong>(vi)</strong> The effect on the workplace and the Employer’s business of making the adjustment including the financial impact, the number of persons who would benefit or be disadvantaged and the impact of efficiency and productivity</p><p><strong>(vii)</strong> The consequences for the Employer in making the adjustment</p><p><strong>(viii)</strong> The consequences for the Employee in not making the adjustment.</p><p><strong>67.4</strong> Reasonable Adjustments Where an Employer knows, or reasonably ought to have known, that an Employee has a disability, the Employer:</p><p><strong>(a)</strong> is required to make reasonable adjustments to enable the Employee to perform the genuine and reasonable requirements of the employment, subject to (b) below; and</p><p><strong>(b)</strong> is not required to make reasonable adjustments if the Employee could not or cannot adequately perform the genuine and reasonable requirements of the employment even after the adjustments are made.</p>',22)])])}const u=t(n,[["render",i]]);export{c as __pageData,u as default};
